mapper.select:
/* RcpCombMgmtMapper.getRcpCombMgmtList */
SELECT A.REQ_SEQ ,B.SCAN_ID ,C.RES_NO ,A.COMB_TYPE_CD ,FN_GET_CODENM('RCP9036' , A.COMB_TYPE_CD) AS COMB_TYPE_NM ,A.M_CTN AS TEL1 ,TO_CHAR(TO_DATE(B.LST_COM_ACTV_DATE , 'YYYY-MM-DD'), 'YYYY-MM-DD') AS M_OPEN_DT ,A.M_CUST_NM AS CSTMR_NAME ,SUBSTR(A.M_CUST_BIRTH , -6) AS M_CUST_BIRTH ,A.M_SEX_CD ,DECODE(A.M_SEX_CD , '01' , '남' , '02' , '여', '03', '법인') AS M_SEX_NM ,A.M_SVC_CNTR_NO ,A.M_RATE_CD ,A.M_RATE_NM ,A.M_RATE_ADSVC_CD ,A.M_RATE_ADSVC_NM ,A.COMB_SVC_NO AS TEL2 ,(SELECT TO_CHAR(TO_DATE(LST_COM_ACTV_DATE , 'YYYY-MM-DD') , 'YYYY-MM-DD') FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.COMB_SVC_CNTR_NO) AS COMB_OPEN_DT ,A.COMB_SVC_CNTR_NO ,A.COMB_CUST_NM AS CSTMR_NAME2 ,SUBSTR(A.COMB_BIRTH , -6 ) AS COMB_BIRTH ,A.COMB_SEX_CD ,DECODE(A.COMB_SEX_CD , '01' , '남' , '02' , '여', '03', '법인') AS COMB_SEX_NM ,FN_GET_CODENM('RCP9038' , A.COMB_TYPE_CD) AS COMB_DTL_TYPE_NM ,A.COMB_SOC_CD ,A.COMB_SOC_NM ,A.COMB_RATE_ADSVC_CD ,A.COMB_RATE_ADSVC_NM ,A.COMB_TGT_TYPE_CD ,FN_GET_CODENM('RCP9039' , A.COMB_TGT_TYPE_CD) AS COMB_TGT_TYPE_NM ,A.RSLT_CD ,FN_GET_CODENM('RCP9037' , A.RSLT_CD) AS RSLT_NM ,A.RSLT_MEMO ,A.SYS_DT ,A.REG_DT ,A.RVISN_ID ,A.RVISN_DTTM FROM MCP_REQ_COMBINE@DL_MCP A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C WHERE A.M_SVC_CNTR_NO = B.CONTRACT_NUM(+) AND A.M_SVC_CNTR_NO = C.CONTRACT_NUM(+)
AND SYS_DT BETWEEN #{strtDt} AND #{endDt}
AND A.M_RATE_ADSVC_NM LIKE '%' || #{searchVal} || '%'
AND A.M_RATE_NM LIKE '%' || #{searchVal} || '%'
AND A.M_RATE_CD LIKE '%' || #{searchVal} || '%'
AND A.M_CTN LIKE '%' || #{searchVal} || '%'
AND A.M_CUST_NM LIKE '%' || #{searchVal} || '%'
AND A.COMB_TYPE_CD = #{combTypeCd}
AND A.RSLT_CD = #{rsltCd}
ORDER BY A.REG_DT DESC

mapper.update:
/* RcpCombMgmtMapper.updateRcpCombRslt */
UPDATE MCP_REQ_COMBINE@DL_MCP
SET RSLT_CD = #{rsltCd, jdbcType=VARCHAR}
, RSLT_MEMO = #{rsltMemo, jdbcType=VARCHAR}
WHERE REQ_SEQ = #{reqSeq}

mapper.select:
		/* RcpCombMgmtMapper.selectMsgTelNo */
		    SELECT M_CTN 
		    FROM MCP_REQ_COMBINE@DL_MCP
            WHERE REQ_SEQ = #{reqSeq}
